import React from 'react';
import { useCurrentFrame, useVideoConfig } from 'remotion';
import { z } from 'zod';
import { DURATION } from '../../../lib/motion';
import { entryFade } from '../../../lib/choreography';

/** Zod schema for {@link FadeIn} props — drives Remotion `defaultProps` validation. */
export const fadeInSchema = z.object({
  /** What to reveal. */
  text: z.string().default('Onda'),
  /** Frames before the animation starts. */
  delay: z.number().int().min(0).default(0),
  /** Frames to fully reach opacity 1. Default `DURATION.base` (18). */
  duration: z.number().int().min(1).default(DURATION.base),
  /** Text color. Defaults to `--onda-text` (`#F2F2F4`). */
  color: z.string().default('#F2F2F4'),
  /** Pixels. */
  fontSize: z.number().default(96),
  /** Onda display font. Never default to Inter / Arial / system. */
  fontFamily: z.string().default('"Clash Display", sans-serif'),
});

/** Inferred props for {@link FadeIn}. */
export type FadeInProps = z.infer<typeof fadeInSchema>;

/**
 * A pure opacity fade for text — no movement, no scale, no blur. The simplest
 * possible reveal in the Onda catalog, for moments where any other motion
 * would say too much.
 *
 * Motion: `entryFade` from `lib/choreography.ts` (`SPRING_SMOOTH`, clamped).
 *
 * @example
 * <FadeIn text="Onda" duration={18} />
 */
export const FadeIn: React.FC<FadeInProps> = ({
  text, delay, duration, color, fontSize, fontFamily,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const { opacity } = entryFade({ frame, fps, delay, durationInFrames: duration });

  return (
    <div style={{
      opacity,
      color, fontSize, fontFamily, fontWeight: 600,
    }}>
      {text}
    </div>
  );
};

// Re-exports the Zod schema so tooling (registry builds, docs site,
// training-data pipelines) can consume props validation without pulling
// in the component itself.
export { fadeInSchema, type FadeInProps } from './FadeIn';

# FadeIn

A pure opacity fade for text. No translate, no scale, no blur — just opacity easing from 0 to 1 with the Onda house curve. The simplest possible reveal in the catalog, for moments where any other motion would say too much.

## Props

| Name | Type | Default | Notes |
| --- | --- | --- | --- |
| `text` | `string` | `"Onda"` | What to reveal. |
| `delay` | `integer ≥ 0` | `0` | Frames before the animation starts. |
| `duration` | `integer ≥ 1` | `DURATION.base` (18) | Frames to fully reach opacity 1. |
| `color` | `string` | `"#F2F2F4"` | Text color — defaults to `--onda-text`. |
| `fontSize` | `number` | `96` | Pixels. |
| `fontFamily` | `string` | `'"Clash Display", sans-serif'` | The Onda display font. Never default to Inter / Arial / system. |

## Usage

```tsx
import { Composition } from 'remotion';
import { FadeIn, fadeInSchema } from './components/onda/fade-in/FadeIn';

export const Root: React.FC = () => (
  <Composition
    id="MyFade"
    component={FadeIn}
    durationInFrames={60}
    fps={30}
    width={1080}
    height={1920}
    schema={fadeInSchema}
    defaultProps={{
      text: 'Hello',
      delay: 0,
      duration: 18,
      color: '#F2F2F4',
      fontSize: 96,
      fontFamily: '"Clash Display", sans-serif',
    }}
  />
);
```

## Motion notes

- Opacity is driven by `entryFade` from `lib/choreography.ts`, which uses `SPRING_SMOOTH` to drive opacity 0→1. Never raw linear for tracked motion.
- Duration defaults to `DURATION.base` (18 frames ≈ 0.6s at 30fps).
- No translate, no scale, no blur — intentionally. When the surrounding scene already carries motion, a pure fade is the right restraint.
- `entryFade` clamps at both ends — the component is correct on frame 0 and on any frame past `delay + duration`.
